## 1.3 Variables and Data Types

### Primitive Data Types:

```java
public class DataTypes {
    public static void main(String[] args) {

        // ── INTEGER TYPES ──────────────────────────────────────
        byte   smallNum   = 127;           // 8-bit  | Range: -128 to 127
        short  medNum     = 32767;         // 16-bit | Range: -32,768 to 32,767
        int    normalNum  = 2147483647;    // 32-bit | Most commonly used
        long   bigNum     = 9876543210L;   // 64-bit | Note the 'L' suffix

        // ── FLOATING POINT TYPES ───────────────────────────────
        float  price      = 19.99f;        // 32-bit | Note the 'f' suffix
        double precise    = 3.14159265358; // 64-bit | Default decimal type

        // ── CHARACTER TYPE ─────────────────────────────────────
        char   letter     = 'A';           // Single character (Unicode)
        char   unicode    = '\u0041';      // Unicode for 'A'

        // ── BOOLEAN TYPE ───────────────────────────────────────
        boolean isJavaFun = true;
        boolean isHard    = false;

        // ── PRINTING ALL ───────────────────────────────────────
        System.out.println("byte:    " + smallNum);
        System.out.println("int:     " + normalNum);
        System.out.println("long:    " + bigNum);
        System.out.println("double:  " + precise);
        System.out.println("char:    " + letter);
        System.out.println("boolean: " + isJavaFun);
    }
}
```

### Reference Types:

```java
public class ReferenceTypes {
    public static void main(String[] args) {

        // String — most used reference type
        String name    = "Alice";
        String greeting = new String("Hello");  // Explicit object creation

        // String operations
        System.out.println(name.length());          // 5
        System.out.println(name.toUpperCase());     // ALICE
        System.out.println(name.charAt(0));         // A
        System.out.println(name.contains("lic"));   // true
        System.out.println(name.replace("A","E"));  // Elice
        System.out.println(name.substring(1, 4));   // lic
        System.out.println("  hello  ".trim());     // hello

        // String concatenation
        String fullName = "Alice" + " " + "Smith";
        System.out.println(fullName);               // Alice Smith

        // String comparison — ALWAYS use .equals(), not ==
        String s1 = "Java";
        String s2 = "Java";
        System.out.println(s1.equals(s2));          // true (correct way)
        System.out.println(s1 == s2);               // true (unreliable!)
    }
}
```

### Type Casting:

```java
public class TypeCasting {
    public static void main(String[] args) {

        // ── WIDENING (Automatic) ───────────────────────────────
        // Smaller type → Larger type (safe, no data loss)
        int    myInt    = 100;
        long   myLong   = myInt;    // int → long (automatic)
        double myDouble = myLong;   // long → double (automatic)

        System.out.println(myInt);    // 100
        System.out.println(myLong);   // 100
        System.out.println(myDouble); // 100.0

        // ── NARROWING (Manual) ─────────────────────────────────
        // Larger type → Smaller type (may lose data!)
        double pi      = 3.99999;
        int    piInt   = (int) pi;  // Truncates decimal part
        System.out.println(piInt);  // 3 (not 4 — truncated, not rounded!)

        // ── STRING CONVERSIONS ─────────────────────────────────
        String numStr  = "42";
        int    parsed  = Integer.parseInt(numStr);
        double parsedD = Double.parseDouble("3.14");
        String fromInt = String.valueOf(100);
        String fromInt2 = Integer.toString(200);

        System.out.println(parsed + 8);   // 50
        System.out.println(parsedD);      // 3.14
        System.out.println(fromInt);      // 100
    }
}
```

